  const store = key => new Set(JSON.parse(localStorage.getItem(key) || '[]').map(String));
  const savedMeta=JSON.parse(localStorage.getItem(syncKeys.meta)||'{}'),savedContext=JSON.parse(localStorage.getItem(syncKeys.context)||'{}');
