  const state = { view: location.hash.slice(1) || 'home', query: '', moveQuery: '', moveType: 'all', moveCategory: 'all', moveVisible: 50, locationFilter: '', type: 'all', sort: 'dex', hideCaught: false, period: 'day', visible: 50, selected: {}, caught: store('radical-red-caught'),team:Array.from({length:6},(_,i)=>({...blankTeamSlot(),...(savedTeam[i]||{}),moves:Array.from({length:4},(__,m)=>savedTeam[i]?.moves?.[m]||'')})),favorites:Array.isArray(savedFavorites)?savedFavorites:[],syncCode:localStorage.getItem(syncKeys.code)||'',saveMeta:{revision:Number(savedMeta.revision)||0,modifiedAt:savedMeta.modifiedAt||null,deviceId:savedMeta.deviceId||crypto.randomUUID()},syncContext:{code:savedContext.code||'',lastSyncedRevision:Number.isInteger(savedContext.lastSyncedRevision)?savedContext.lastSyncedRevision:null,lastSyncedFingerprint:savedContext.lastSyncedFingerprint||'',lastSyncedAt:savedContext.lastSyncedAt||null},syncStatus:'unchecked',syncSnapshot:null,cloudHistory:[] };
  let dexObserver = null;
