  function renderHome(){ return `<section class="hero"><div class="hero-copy"><img class="hero-logo" src="assets/art/radical-red-logo.png" alt="Pokémon Radical Red"><h1>Field Guide</h1><div class="hero-actions"><button class="primary" data-view="pokedex">Open the Pokédex</button><button class="secondary" data-view="locations">Explore locations</button></div></div></section><section class="metrics"><article><strong>${groups.length}</strong><span>Dex entries</span></article><article><strong>${data.pokemon.length}</strong><span>Forms documented</span></article><article><strong>${data.locations.length}</strong><span>Grass & cave locations</span></article><article><strong>${state.caught.size}</strong><span>Caught</span></article></section><div class="section-title"><span class="eyebrow">START HERE</span><h2>Your field kit</h2></div><section class="feature-grid"><button data-view="pokedex"><i>◉</i><b>Complete Pokédex</b><span>Search, filter, inspect stats and mark catches.</span></button><button data-view="locations"><i>☀</i><b>Day & night encounters</b><span>Keep the workbook's paired tables clear and separate.</span></button><button data-view="progress"><i>✓</i><b>Completion tracker</b><span>See exactly how far your current run has come.</span></button></section>`; }
  function filteredGroups(){ const q=norm(state.query), statIndex={hp:0,attack:1,defense:2,speed:3,spatk:4,spdef:5}; const found=groups.filter(g=>g.forms.some(p=>(!q || norm(p.name).includes(q) || String(p.dexId).includes(q)) && (state.type==='all'||p.types.includes(state.type))) && (!state.hideCaught||!state.caught.has(g.dexId))); return found.sort((a,b)=>{const pa=activeForm(a),pb=activeForm(b);if(state.sort==='az')return pa.name.localeCompare(pb.name);if(state.sort==='za')return pb.name.localeCompare(pa.name);if(state.sort==='bst')return pb.bst-pa.bst||Number(a.dexId)-Number(b.dexId);if(statIndex[state.sort]!=null)return (pb.stats[statIndex[state.sort]]||0)-(pa.stats[statIndex[state.sort]]||0)||Number(a.dexId)-Number(b.dexId);return Number(a.dexId)-Number(b.dexId);}); }
  function card(group){ const p=activeForm(group), caught=state.caught.has(group.dexId); return `<article class="poke-card" data-species="${group.dexId}" style="--accent:${p.typeColours[0]||'#d12b42'}"><div class="card-top"><span>#${String(group.dexId).padStart(4,'0')}</span><button class="caught-ball ${caught?'caught':''}" data-caught="${group.dexId}" title="${caught?'Mark not caught':'Mark caught'}" aria-label="${caught?'Caught':'Not caught'}"><img src="assets/ui/pokeball.svg" alt=""></button></div><div class="poke-summary"><img src="${p.sprite}" alt="${esc(p.name)}"><div class="pokemon-identity"><div><h3>${esc(p.name)}</h3>${types(p)}</div><strong class="bst-value">${p.bst} <small>BST</small></strong></div></div>${group.forms.length>1?`<div class="form-row"><button data-step="-1" data-group="${group.dexId}" aria-label="Previous form">‹</button><span>${esc(formName(group,p))}</span><button data-step="1" data-group="${group.dexId}" aria-label="Next form">›</button></div>`:'<div class="form-row form-placeholder" aria-hidden="true"><span>&nbsp;</span></div>'}<button class="info-button" data-pokemon="${p.id}">Info</button></article>`; }
  function controls(){ const allTypes=[...new Set(data.pokemon.flatMap(p=>p.types))].sort(), sorts=[['dex','Dex number'],['az','A–Z'],['za','Z–A'],['bst','BST'],['hp','HP'],['defense','Defense'],['spdef','Sp. Def'],['attack','Attack'],['spatk','Sp. Atk'],['speed','Speed']]; return `<section class="controls"><div class="search-row"><input id="dexSearch" type="search" placeholder="Search by name or number…" value="${esc(state.query)}"><label class="sort-control"><span>Sort by</span><select id="sortBy">${sorts.map(([value,label])=>`<option value="${value}" ${state.sort===value?'selected':''}>${label}</option>`).join('')}</select></label><label><input id="hideCaught" type="checkbox" ${state.hideCaught?'checked':''}> Hide caught</label></div><div class="chips"><button class="${state.type==='all'?'active':''}" data-type="all">All</button>${allTypes.map(t=>`<button class="${state.type===t?'active':''}" data-type="${esc(t)}">${esc(t)}</button>`).join('')}</div></section>`; }
  function renderDex(){ const found=filteredGroups(), visible=found.slice(0,state.visible); return `<header class="page-head"><div><span class="eyebrow">RADICAL RED v4.1</span><h1>Pokédex</h1><p>${found.length} entries match · ${state.caught.size} caught</p></div></header>${controls()}<section class="dex-grid">${visible.map(card).join('')||'<p class="empty">No Pokémon match those filters.</p>'}</section>${visible.length<found.length?'<div id="loadSentinel" class="load-sentinel"><span></span><span></span><span></span><small>Loading more Pokémon</small></div>':''}`; }
