  function moveCard(move){ return `<article class="move-card" data-move="${move.id}" style="--move-type:${move.typeColour}"><header><div>${moveTypePill(move)}<span class="move-category ${move.category.toLowerCase()}">${esc(move.category)}</span></div><strong>${move.pp??'—'} PP</strong></header><h3>${esc(move.name)}</h3><div class="move-numbers"><span><small>Power</small><b>${move.power??'—'}</b></span><span><small>Accuracy</small><b>${move.accuracy?move.accuracy+'%':'—'}</b></span></div><p>${esc(move.description||'No description available.')}</p><button class="info-button" data-move-info="${move.id}">Info</button></article>`; }
  function renderMoves(){ const found=filteredMoves(),visible=found.slice(0,state.moveVisible),types=[...new Set((data.moves||[]).map(move=>move.type))].sort();return `<header class="page-head"><div><span class="eyebrow">BATTLE LIBRARY</span><h1>Moves</h1><p>${found.length} moves match</p></div></header><section class="move-controls"><input id="moveSearch" type="search" placeholder="Search moves or descriptions…" value="${esc(state.moveQuery)}"><select id="moveTypeFilter"><option value="all">All types</option>${types.map(type=>`<option value="${type}" ${state.moveType===type?'selected':''}>${type}</option>`).join('')}</select><select id="moveCategoryFilter"><option value="all">All categories</option>${['Physical','Special','Status'].map(category=>`<option value="${category}" ${state.moveCategory===category?'selected':''}>${category}</option>`).join('')}</select></section><section class="move-grid">${visible.map(moveCard).join('')||'<p class="empty">No moves match those filters.</p>'}</section>${visible.length<found.length?'<div id="moveLoadSentinel" class="load-sentinel"><span></span><span></span><span></span><small>Loading more moves</small></div>':''}`; }
