  function pokemonMovesSection(p){ const level=(p.learnset?.level||[]).map(item=>({...item,move:moveById.get(item.moveId)})).filter(item=>item.move),tm=[...new Set(p.learnset?.tm||[])].map(id=>moveById.get(id)).filter(Boolean),tutor=[...new Set(p.learnset?.tutor||[])].map(id=>moveById.get(id)).filter(Boolean);const group=(title,items,levelled=false)=>`<div class="pokemon-move-group"><h4>${title}</h4>${items.length?`<div class="pokemon-move-list">${items.map(item=>{const move=levelled?item.move:item;return `<button data-move-info="${move.id}">${moveTypePill(move)}<span><strong>${esc(move.name)}</strong>${levelled?`<small>Level ${item.level}</small>`:''}</span><b>${move.power??'—'}</b></button>`}).join('')}</div>`:'<p>None documented.</p>'}</div>`;return `<section class="pokemon-moves"><h3>Moves</h3>${group('Level up',level,true)}${group('TM',tm)}${group('Move Tutor',tutor)}</section>`; }
  function openMove(id){ const move=moveById.get(Number(id));if(!move)return;const learners=moveLearners(move.id);dialog.querySelector('#dialogContent').innerHTML=`<button class="dialog-close" aria-label="Close">×</button><div class="move-detail" style="--move-type:${move.typeColour}"><span class="eyebrow">MOVE DATABASE</span><h2>${esc(move.name)}</h2><div class="move-detail-tags">${moveTypePill(move)}<span class="move-category ${move.category.toLowerCase()}">${esc(move.category)}</span></div><div class="move-detail-stats"><div><small>Power</small><strong>${move.power??'—'}</strong></div><div><small>Accuracy</small><strong>${move.accuracy?move.accuracy+'%':'—'}</strong></div><div><small>PP</small><strong>${move.pp??'—'}</strong></div><div><small>Priority</small><strong>${move.priority}</strong></div></div><p>${esc(move.description||'No description available.')}</p></div><section class="move-learners"><h3>Pokémon that learn this move</h3><p>${learners.length} documented forms</p><div>${learners.map(entry=>`<button data-evo-pokemon="${entry.pokemon.id}"><img src="${entry.pokemon.sprite}" alt=""><span><strong>${esc(displayPokemonName(entry.pokemon))}</strong><small>${esc(entry.methods.join(' · '))}</small></span><b>→</b></button>`).join('')}</div></section>`;dialog.showModal();dialog.querySelector('.dialog-close').onclick=()=>dialog.close();bind(dialog); }
