  function normalizeSyncCode(value=document.querySelector('#syncCode')?.value||state.syncCode){const code=value.trim().toUpperCase().replace(/[^A-Z2-9]/g,'').match(/.{1,4}/g)?.join('-')||'';if(!syncCodePattern.test(code))throw new Error('Enter a complete 12-character sync code.');state.syncCode=code;localStorage.setItem(syncKeys.code,code);if(state.syncContext.code!==code){state.syncContext={code,lastSyncedRevision:null,lastSyncedFingerprint:'',lastSyncedAt:null};localStorage.setItem(syncKeys.context,JSON.stringify(state.syncContext))}return code}
