  function syncMessage(status,snapshot=state.syncSnapshot){const date=snapshot?.cloudSave?.sync?.modifiedAt||snapshot?.envelope?.updatedAt;return({unchecked:['Not checked','Check the cloud before moving to another device.'],checking:['Checking…','Comparing this device with the encrypted cloud copy.'],'no-cloud':['No cloud save yet','Save this device to create the first cloud copy.'],'in-sync':['In sync',`Both copies match. Latest cloud save: ${saveDate(date)}.`],'local-newer':['This device is newer','Save to cloud before continuing on another device.'],'cloud-newer':['Cloud save is newer',`Load the cloud copy from ${saveDate(date)} before making changes here.`],conflict:['Changes on both devices','Choose which copy to keep. Nothing has been overwritten.'],error:['Could not check','Your local progress is unchanged.']})[status]||['Not checked','Check the cloud before moving devices.']}
  function classify(localFp,cloudFp,cloudSave){if(!cloudSave)return'no-cloud';if(localFp===cloudFp)return'in-sync';if(!state.syncContext.lastSyncedFingerprint)return(state.caught.size||state.team.some(slot=>slot.pokemonId)||state.favorites.length)?'conflict':'cloud-newer';const l=localFp!==state.syncContext.lastSyncedFingerprint,c=cloudFp!==state.syncContext.lastSyncedFingerprint;return l&&c?'conflict':c?'cloud-newer':l?'local-newer':'in-sync'}
